                      my_irq_handler,    // 中断处理函数
                      IRQF_TRIGGER_RISING, // 触发方式：上升沿
                      "my_irq_dev",      // 设备名
                      NULL);             // dev_id，可用于共享中断
    if (ret) {
        printk(KERN_ERR "Failed to request IRQ\n");
        return ret;
    }
